var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"흠~ 흐흠~ 흠~","JPN":"ふん～ふふん～ふん～","ENG":"Hmm~ hmm~ hmm~","TWN":"哼～哼哼～哼～"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L4_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"너 때문에 조용히 끝날 일을 너무 크게 벌렸다는 생각 안 들어?","JPN":"君のせいで、穏便に済ませられることが、こんなになったとは思わないの？","ENG":"Don’t you think you’ve made a mess too big? It could've quietly ended.","TWN":"你不覺得，事情原本可以低調解決的，結果因為你的關係鬧很大嗎？"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"어디에 숨어서 훼방을 놓길래 학회 회원들이 전부 연락이 끊겼나 했는데…….","JPN":"隠れて邪魔をするから、学会の会員たちが連絡を全部切っちゃったのかと思ったら……","ENG":"Losing communication with Society members, I was wondering where you were hiding and being such a nuisance.","TWN":"還想說是躲在哪裡礙事，怎麼和學會都聯絡不上……"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"우후후. 막바지까지 악보를 노린 건 <color=#ffd34c>참 잘했어요</color> 라고 해 줄게.","JPN":"うふふ。最後まで楽譜を狙ったことは<color=#ffd34c>よくできました</color>って褒めてあげる。","ENG":"Fuu fuu... You were after the score till the very end. <color=#ffd34c>Wonderful job, really.</color>","TWN":"呵呵呵，這麼堅持要拿到樂譜，是該好好誇獎一下，<color=#ffd34c>好棒喔</color>。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"이름이…… 모런이라고 했던가?","JPN":"名前が……モーランって言ったっけ？","ENG":"You said your name was... Moran? Was that it?","TWN":"你叫……摩爾？"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HEAD_GRONIA_NULL_NULL","text":{"KOREA":"큭…….","JPN":"くっ……","ENG":"Argh…","TWN":"咳……"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HEAD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"모건……. 새디어스 모건이다.","JPN":"モーガン……タデウス・モーガンだ。","ENG":"Morgan... It’s Thaddeus Morgan.","TWN":"我叫摩根……薩迪烏斯·摩根。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L12_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"그래, 모런. 기르지 않는 인간의 이름 따위는 구분만 할 수 있으면 아무래도 좋잖아?","JPN":"はい、モーラン。飼わない人間の名前なんて、見分けがつけばどうでもいいよね？","ENG":"Okay, Moran. Should I really care about the names of humans I haven’t raised? At least, I could recognize you.","TWN":"嗯嗯，摩爾。不是我養的人類叫什麼都不重要，反正只要能分辨就好。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"그러니까 거기 그렇게 쓰러져 있어, 모런. 내가 준비해 준 특등석이야.","JPN":"だからそこにそのまま倒れていて、モーラン。私の用意した特等席よ。","ENG":"So please fall down over there, Moran. It is the best seat I arranged just for you.\\n","TWN":"總之摩爾，你就躺在那吧，那是我特別為你準備的貴賓席。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"이번 연주는 관객이 한 명이라도 더 많을수록 좋거든.","JPN":"今回の演奏は観客が一人でも多いほうがいいからね。","ENG":"For this performance, the bigger the audience, the better.","TWN":"反正這次的演出觀眾越多越好。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"확실한 빈틈을 포착했다고 생각했는데……. 나이는 못 속이는가 보군…….","JPN":"確実に隙を突いたと思ったが……年は争えないな……","ENG":"I thought I had finally found a weak point... But I can't hide my age...","TWN":"我還以為我掩飾得很好……看來是年紀露餡兒……"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"아가씨, 들리십니까?","JPN":"お嬢様、聞こえますか？","ENG":"Lady, can you hear me?","TWN":"小姐，有聽到嗎？"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"잘 들려요. 모건 아저씨.","JPN":"聞こえますわ、モーガンおじさま。","ENG":"Loud and clear, Mr. Morgan.","TWN":"有聽到，摩根叔。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"제가 단독 행동은 물벼룩 교육에 해로우니 자제하라고 하지 않았던가요?","JPN":"単独行動はミジンコの教育によくないから慎みなさいって言ってませんでしたっけ？","ENG":"Did I not tell you to refrain from acting alone as it’s harmful to Water Flea’s education?","TWN":"我不是說過單獨行動對於教育水蚤是負面教材，請你克制一下嗎？"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"……하하, 그러게나 말입니다.","JPN":"……はは、そうですな。","ENG":"...Ha ha, yes you did say that.","TWN":"……哈哈，小姐說的是。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"이제 학부장 정도 급수는 힘에 부치는군요. 슬슬 은퇴도 생각해야겠습니다.","JPN":"今や学部長レベルも手に負えませんね。そろそろ引退も考えなければ。","ENG":"Dealing with a dean-level is just too much these days. I need to think about retiring.","TWN":"現在連學院長的程度也有點吃力呢，看來是該退休囉。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"실패했다면 어쩔 수 없죠.","JPN":"失敗したのなら仕方ありませんね。","ENG":"If you’ve failed, just move on.","TWN":"失敗的話也沒辦法，"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"저희들의 최선은 악보를 탈환하고, 레버넌트란 인물이 아무것도 모른 채 상황을 종결짓는 것이지만…….","JPN":"私たちの最善は楽譜を奪還し、レヴナントという人物に何も悟られずに状況を終わらせることでしたが……","ENG":"Our best bet is to retrieve the music score and resolve the situation without Revenant knowing anything about it.","TWN":"最好的結果就是拿回樂譜，在假裝不知道亡靈是誰的情況下結束這一切……"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"……네. 지금 바로 <color=#ffd34c>오래된 목소리</color>에게 연락해 주십시오.","JPN":"……はい。今すぐ<color=#ffd34c>古い声</color>にご連絡を。","ENG":"...Agreed. Please contact <color=#ffd34c>Old Voice</color> immediately.","TWN":"……是，請立刻聯繫<color=#ffd34c>老聲音</color>。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"이 늙은이보다, 더 쓸 만한 전력을 보내 줄 겁니다.","JPN":"この年寄りより、もっと使える戦力を送ってくれるはずです。","ENG":"They’ll dispatch someone more useful than this old man.","TWN":"比起我這老人，他應該會派更卓越的戰力來。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"연장자 대접해 줄 마음 없으니 나이 먹은 기색 내비치지 마시죠.","JPN":"年長者に対する礼儀なんてものはありませんから、年寄りをアピールするのはおやめなさい。","ENG":"I don't care how old you are, so please stop showing your age.","TWN":"我沒興趣和長輩相處，請不要把老掛在嘴邊。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"곧 구출팀을 보낼 예정이랍니다. 그 때까지만 버티도록 하세요.","JPN":"すぐに救出班を送る予定ですわ。彼らが着くまで耐えてください。","ENG":"We’ll be sending a rescue team soon. Just hang on until then.","TWN":"救援組很快就會出動，再撐一下。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"……이제 기관만으로는 학회에 대응하기 힘들겠군.","JPN":"……もはや機関だけで学会に対応することは難しそうだ。","ENG":"...It will be difficult for the Institution to respond to the Society alone.","TWN":"……接下來單憑機關似乎難以應付學會。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L34_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"못난 후배들이라 면목이 없습니다. 버넷 형님.","JPN":"不甲斐ない後輩で面目ありません。バーネット兄貴。","ENG":"We’ve got no face to see you, Burnett.","TWN":"伯內特哥，我們這麼沒出息，真是沒臉見你。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>올바른 보도, 진실된 정보. 그로니아 국영 뉴스입니다. </color>","JPN":"<color=#ffd34c>正しい報道、真なる情報。グロニア国営ニュースです。</color>","ENG":"<color=#ffd34c>Reporting in with the truth, Gronia National News.</color>","TWN":"<color=#ffd34c>真實的報導，正確的資訊，格羅尼亞國境新聞。</color>"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L38_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>들리십니까, 국민 여러분?</color>","JPN":"<color=#ffd34c>聞こえますか、国民の皆さん？</color>","ENG":"<color=#ffd34c>Are you listening, good citizens?</color>","TWN":"<color=#ffd34c>各位觀眾，你們有聽到嗎？</color>"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>20년 간 숱한 시련을 견뎌 온 건국기념전당에, 마침내 웅장한 음악 소리가 다시 울려 퍼지고 있습니다. </color>","JPN":"<color=#ffd34c>20年間、数多くの試練に耐えてきた建国記念館に、ついに雄大な音楽の音がふたたび響き渡っています。</color>","ENG":"<color=#ffd34c>At the National Foundation Hall, which has endured so much for over 20 years, the magnificent sound of music is finally heard again. </color>","TWN":"<color=#ffd34c>20年來經歷無數的考驗，建國紀念堂終於再次響起磅礡的音樂聲。</color>"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"방금 막 폭발물 해체가 끝났어. 레버넌트 씨.","JPN":"爆発物の解体が終わったところよ、レヴナントさん。","ENG":"I just finished disarming the explosives, Revenant.","TWN":"亡靈，剛才已經拆彈完畢。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L43_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"이럴 때 해야 할 말이 뭐가 있으려나?","JPN":"こんな時に何か言わなくちゃいけない言葉があったんじゃない？","ENG":"Now, what are you supposed to say at a time like this?","TWN":"這種時候要說什麼呢？"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"덕분에 살았어. 고마워, 알렉스 씨.","JPN":"おかげで助かったよ。ありがとう、アレックスさん。","ENG":"You saved my life. Thank you, Alex.","TWN":"謝謝你，雅蕾克絲，你是我的救命恩人。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"후훗. 좋아. 완벽해.","JPN":"ふふっ。いいね。完璧よ。","ENG":"Fuu fuu. Good. Perfect.","TWN":"呵呵，非常好，很乖～"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L46_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"하지만…… 이 나라를 떠나지 않겠다는 발상은 불합격이야.","JPN":"でも……この国から離れないという発想は不合格ね。","ENG":"But... The idea of not leaving this country is a failure.","TWN":"不過……不離開這個國家的決定不太乖。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"사실 선약이 있었거든. 상황이 급해서 말하지 못했어.","JPN":"実は先約があったんだ。急いでいて話せなかった。","ENG":"To be honest, I already had other plans. I was in a hurry so I didn’t have time to explain.","TWN":"這是之前就決定好的，只是情況緊急來不及跟你說。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"……건국기념전당으로 와. 자세한 이야기는 거기서 하자.","JPN":"……建国記念館に来て。詳しい話はあそこでしよう。","ENG":"...Come to the National Foundation Hall. We’ll talk about the details there.","TWN":"……來建國紀念堂，詳細情形到那邊再說。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>공연이 열리기 전, 총리님께서 발표하신 담화에 따라 극비리에 초청된 온건파 반군 수뇌부와 평화 협정이 논의될 예정입니다.</color>","JPN":"<color=#ffd34c>公演が始まる前、総理が発表した談話に従い、極秘に招かれた穏健派反乱軍の首脳と平和協定の論議が行われる予定です。</color>","ENG":"<color=#ffd34c>Before the performance begins, a peace agreement will be discussed with leaders from the moderate rebels who were secretly invited, as previously announced by the Prime Minister.</color>","TWN":"<color=#ffd34c>在演出前夕，根據總理發表的談話，政府將與溫和派叛軍的首腦進行和平協議。</color>"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>이들은 과거 반정부 단체 시절 요구했던 개혁안을 일부 수용한다면 협정에 긍정적으로 작용할 것이라며…….</color>","JPN":"<color=#ffd34c>彼らは、過去反政府団体だった頃に要求していた改革案を一部受容するなら、協定にいい影響を及ぼすと……</color>","ENG":"<color=#ffd34c>They have stated that if some of the reforms suggested when they were known as the anti-government organization are put into place, they will begin to work positively towards an agreement.</color>","TWN":"<color=#ffd34c>政府表示，若是接受部分過去反政府團體提出的訴求，將對協議達到正面的效果……</color>"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"……다짜고짜 평화 협정이라니, 퍽이나 잘 되겠네요.","JPN":"……いきなり平和協定だなんて、うまく行くと思っているのでしょうか。","ENG":"...A peace agreement all of a sudden? Ha, wouldn’t that be great.","TWN":"……竟然要進行和平協議，還真是棒呢！"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L8_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"왜? 중사는 못 믿겠어?","JPN":"なんで？　軍曹は信用できないの？","ENG":"Oh? You don’t believe it, Sergeant?","TWN":"為什麼這麼說？你不相信嗎？"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"타나베린에서야 거지들도 이터니움 가루는 들고 다니지만, 다른 지역은 그마저도 귀중하니까요.","JPN":"タナベリンじゃエタニウムの粉は貧乏人でも所持していますが、他の地域じゃそれさえも貴重ですから。","ENG":"Only in Tanaberin do beggars carry around Eternium, but in other regions, even that is valuable.","TWN":"只有在達那貝林，才是連乞丐都能取得永恆之金粉末，但在其他地區還是很珍貴的。"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"침식파에 오래 노출되면 사람이 망가져요. 육체적으로나, 정신적으로나.","JPN":"侵食波に長期間露出されると人は壊れます。肉体的にも、精神的にも。","ENG":"Long exposure to Corruption rays will destroy you, physically and mentally.","TWN":"人若長期暴露在侵蝕波之中，無論是身體或是精神上，都會遭到毀壞。"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"맛이 간 인간들이 전쟁터에 와서 무슨 짓을 하는지 알면 놀랄 걸요.","JPN":"壊れた人が戦場に来て何をするか、知ったら驚きますよ。","ENG":"You’d be surprised to know what horrible things people are doing on the battlefield.","TWN":"像這樣不正常的人，上戰場後會做出什麼事，光想就覺得可怕。"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"……그래.","JPN":"……そう。","ENG":"...I see.","TWN":"……說得沒錯。"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그래도 얘기할 수 있다는 게 어디야.","JPN":"でも、話せるだけマシでしょ？","ENG":"Well, at least we are able to talk with them.","TWN":"不過這裡至少還有言論自由。"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"이민은 왜 안 가겠다는 거예요? 제가 제안 받았으면 수송기를 고쳐서라도 갔을 텐데.","JPN":"どうして移民を拒むんですか？　私が提案されたら輸送機を直してでも移民してました。","ENG":"Why not immigrate to another country? If I’d have gotten the same offer, I would have fixed that transport and been on my way in a jiffy.","TWN":"你為什麼不移民？要是我收到這樣的提議，一定立刻修好運輸機走人！"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그렇긴 한데, 엄마는 집이 최고라고 하니까.","JPN":"そうだけど、お母さんは家が最高だって言うから。","ENG":"Sure, but my mom says that there’s no place like home.","TWN":"話是沒錯，但我媽總說家是最棒的。"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"적어도 안젤라가 돌아올 때까지는……. 여기 있고 싶어.","JPN":"せめて、アンジェラが帰ってくるまでは……ここにいたい。","ENG":"I want to stay here... At least until Angela gets back.","TWN":"至少在安潔拉回來之前……我想先留在這裡。"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"엄마, 알고 있었어?","JPN":"お母さん、知ってた？","ENG":"Did you know, Mom?","TWN":"媽，你知道嗎？"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"오늘 공연에서 엄마가 쓴 곡이 연주된대.","JPN":"今日の公演、お母さんが書いた曲が演奏されるって。","ENG":"The song you wrote will be played at the concert today.","TWN":"今天的音樂會中會演奏媽做的曲子喔。"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"으응……?","JPN":"んん……？","ENG":"...H-huh?","TWN":"嗯……？"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"그래, 지휘자 총각이 그것 때문에 집에 찾아왔었구나…….","JPN":"なるほど、指揮者が家に来たのはそのためだったのね……","ENG":"I see. That’s why that conductor stopped by our home.","TWN":"是啊，指揮家還特地找到家裡來呢……"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"고마운 일이야…… 정말 고마워……","JPN":"ありがたいことね……本当に……","ENG":"I’m so honored...Truly grateful...","TWN":"真是感恩……真的很感恩……"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L29_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>다음 차례는 기념식의 마지막이자, 평화의 시작을 축하하는 곡입니다.</color>","JPN":"<color=#ffd34c>次は記念式の最後であり、平和の始まりを祝う曲です。</color>","ENG":"<color=#ffd34c>The next piece marks the end of the ceremony. It is a song celebrating the beginning of peace.</color>","TWN":"<color=#ffd34c>下一首曲子，是此次演奏會的最後一首，是象徵和平的曲子。</color>"},"stage":{"bg":"HARMONY_03","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>여러분, 루이제 슈나이더를 아십니까?</color>","JPN":"<color=#ffd34c>皆さん、ルイーゼ・シュナイダーをご存じでしょうか？</color>","ENG":"<color=#ffd34c>Everyone, do you remember Louise Schneider?</color>","TWN":"<color=#ffd34c>大家還記得露易絲·修奈德嗎？</color>"},"stage":{"bg":"HARMONY_03","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>루머에 시달린 끝에 힘겨운 노년을 보내고 있는 그녀가, 화해와 평화의 염원을 담아 써 내려간 곡입니다.</color>","JPN":"<color=#ffd34c>悪い噂に悩まされ、辛い老年を送っている彼女が和解と平和の願いを込めて書いた曲です。</color>","ENG":"<color=#ffd34c>She wrote this song yearning for reconciliation and peace, despite all the horrible rumors and all of her hardships at her age.</color>","TWN":"<color=#ffd34c>她受到謠言中傷後，老年生活非常辛苦，而這首曲子，就是她在期盼和平的心情下所寫的。</color>"},"stage":{"bg":"HARMONY_03","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"크리스티나 브레히트 중사.","JPN":"クリスティーナ・ブレヒト軍曹。","ENG":"Sergeant Christina Brecht.","TWN":"克莉絲蒂娜·布萊希特中士。"},"stage":{"bg":"HARMONY_03","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"응? 가, 갑자기 왜 풀네임으로 불러요?","JPN":"ん？　い、いきなりなんでフルネームで呼ぶんですか？","ENG":"Huh? W-Why did you call me by my full name all of a sudden?","TWN":"嗯？怎麼突然叫我的全名？"},"stage":{"bg":"HARMONY_03","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"귀관의 공헌에 감사합니다.","JPN":"貴官の貢献に感謝します。","ENG":"Thank you for all you’ve done.","TWN":"謝謝中士的貢獻。"},"stage":{"bg":"HARMONY_03","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"귀관이 아니었으면…… 이 풍경은 볼 수 없었을 겁니다.","JPN":"貴官がいなかったら……この景色を見ることは叶いませんでした。","ENG":"If it weren’t for you... We never would have been able to witness this moment.","TWN":"因為中士……才能看到這樣的場景。"},"stage":{"bg":"HARMONY_03","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그…… 그만하죠. 이런 때에 놀림 받긴 싫은데요.","JPN":"そ……その辺にしてください。こんな時にからかわれたくないです。","ENG":"S-Stop it. I hate this kind of sarcasm.","TWN":"少……少來，我現在沒心情跟你開玩笑啦。"},"stage":{"bg":"HARMONY_03","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"후훗. 진심으로 하는 얘기야.","JPN":"ふふっ。本気で言ってるの。","ENG":"Fuu fuu. I mean it.","TWN":"呵呵，我是認真的。"},"stage":{"bg":"HARMONY_03","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"……다 알고 있잖아요. 훈장 같은 거 그냥 병사들 사기진작용으로 줬다는 거.","JPN":"……知ってるでしょう。勲章なんて、兵士の士気を高めるためにあげたってこと。","ENG":"...You know, right? I had no business getting awarded that medal.","TWN":"……你也很清楚吧，頒發勳章的目的，大多是因為要鼓舞士氣。"},"stage":{"bg":"HARMONY_03","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"전 그냥…… 제대로 싸울 줄도 모르고 빠져나갈 궁리만 하는 얼치기라고요.","JPN":"私はただ……ろくな戦い方も知らない、逃げることだけ考えている半端者ですよ。","ENG":"I’m just... an idiot that doesn’t know how to fight and always tries to escape.","TWN":"而我……根本不知道怎麼打仗，整天只想著怎麼脫身，說穿了就是個二百五。"},"stage":{"bg":"HARMONY_03","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그렇지 않아. 중사.","JPN":"違うよ、軍曹。","ENG":"That’s not true, Sergeant.","TWN":"不是的，中士。"},"stage":{"bg":"HARMONY_03","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"나에게는…… 적어도 나랑 엄마에게는, 무공훈장 수훈자다운 군인이었어.","JPN":"私には……少なくとも私とお母さんには、勲章の受勲者らしい軍人だった。","ENG":"To me... At least to my mom and I, you are a war hero worthy of the Medal of Honor.","TWN":"對我來說……或是至少對我和我媽來說，你是值得獲得勳章的軍人。"},"stage":{"bg":"HARMONY_03","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"HARMONY_03","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"레버넌트 씨, 저는…….","JPN":"レヴナントさん、私は……","ENG":"Revenant, I...","TWN":"亡靈小姐，我……"},"stage":{"bg":"HARMONY_03","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"……어?","JPN":"……え？","ENG":"...Huh?","TWN":"……嗯？"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"왜 그래, 중사?","JPN":"どうしたの、軍曹？","ENG":"What's wrong, Sergeant?","TWN":"怎麼了，中士？"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L7_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"자, 잠시만요? 이게 왜 이러지?","JPN":"ちょ、ちょっと？　どうなってるの？","ENG":"W-Wait a second. That’s strange.","TWN":"等…等等？這個怎麼這樣？"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"CRF가…… 이렇게 금방 줄어드는 거였나?","JPN":"CRFって……こんなすぐ減るものだっけ？","ENG":"CRF... Is it supposed to decrease this quickly?","TWN":"CRF……怎麼會減少得這麼快？"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"양동 작전이었다고? 처음부터?","JPN":"陽動作戦だったの？　最初から？","ENG":"Was the operation a feint? From the very beginning?","TWN":"從一開始就打算聲東擊西嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"네. 아티팩트는 카멜롯 전대가 건재하던 시절부터 저희 쪽 소관이었니까요.","JPN":"ええ。アーティファクトはキャメロット戦隊が健在した頃からずっと私たちの所管でしたから。","ENG":"Quite right. Artifact has been under our jurisdiction ever since the days of the Camelot Division.","TWN":"是，畢竟卡梅羅戰隊還在時，人造神器就一直都是由我們保管。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"학회의 지원을 차단하는 것까지는 성공했지만, 그림자가 하나 더 숨어 있던 건 상정 외의 변수였어요.","JPN":"学会の支援を食い止めることまでは成功しましたが、シャドウがもう一つ潜んでいたことは想定外でした。","ENG":"We succeeded in disrupting the Society’s support, but another Shadow was unexpectedly hidden and unaccounted for.","TWN":"雖然已經成功切斷學會的支援，但沒想到有變數，就是另一個躲起來的暗影。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"학회와 끈이 닿아 있는 정부 인사가 의도적으로 정보를 차단한 흔적도…….","JPN":"学会と繋がっている政府の人物が意図的に情報を消した痕跡も……","ENG":"There were also signs that government officials connected with the Society have deliberately withheld information.","TWN":"和學會接上線的政府人士刻意斷絕情報的痕跡也……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"고상한 소리 집어치워, 귀족 아가씨. 난 탄약고에서 자라서 그런 얘기 취향이 아냐.","JPN":"上品なこと言うのはやめなさい、貴族のお嬢さん。私は弾薬庫で育ったからそういう話は向いてないの。","ENG":"Speak plainly, lady. I grew up in an ammunition dump and I don’t take kindly to using so many words when only a few will do.","TWN":"貴族小姐，收起你的長篇大論，我是在彈藥庫裡長大的，聽不慣這些。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"요점만 말해. 그 악보가 연주되면 어떻게 되는데?","JPN":"結論だけ言って。その楽譜が演奏されるとどうなるの？","ENG":"Just get to the point. What happens when the score is played?","TWN":"說重點就好，演奏那個樂譜會發生什麼事？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"저희 측 자료를 분석한 결과로는, 그 지역에 잔류 중인 침식파를 끌어모으게 된답니다.","JPN":"こちら側の資料で分析した結果、その地域に残留している侵食波をかき集めるそうですわ。","ENG":"Analysis shows that the melody will attract all Corruption rays remaining in the area.","TWN":"根據我們分析資料的結果，殘留的侵蝕波會匯集到那個地區。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"사용하기에 따라서는 국토 전역을 아우를 수도 있어요.","JPN":"使い方次第では全土に影響を及ぼすことでしょう。","ENG":"Depending on how they are used, it could engulf the entire country.","TWN":"根據使用情況，可能會擴及國土全境。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"……이 나라에는 수도 근방에도 방치된 침식지대가 수없이 많아.","JPN":"……この国には首都の近くにも放置されている侵食地帯がたくさんある。","ENG":"...There are countless Corrupted Areas in this country that have been neglected. Even near the capital.","TWN":"……在這個國家，光是在近郊就有許多荒廢的侵蝕地帶。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"네. 그래서 여기서 모든 것을 진행하기로 택했는지도 몰라요.","JPN":"ええ。だからここですべてを進めることにしたのかもしれませんわ。","ENG":"Indeed. Perhaps that’s why she chose to proceed with everything here.","TWN":"是，所以可能會選擇在這裡進行。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"마에스트로란 그림자가 스스로를 재구축하기에…… 충분한 양일 테니까요.","JPN":"マエストロというシャドウが自らを再構築するには……十分な量ですから。","ENG":"It should be sufficient... for the Shadow of Maestra to reconstruct herself.","TWN":"因為量足以讓那個叫指揮家的暗影……重生。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};